const fs = require('fs');
const path = require('path');
const pdf = require('pdf-parse');

const SRC = process.argv[2];
const DST = process.argv[3];

if (!SRC || !DST) {
  console.error('usage: node convert.js <pdf> <md>');
  process.exit(1);
}

const dataBuffer = fs.readFileSync(SRC);

pdf(dataBuffer).then(data => {
  let text = data.text;

  // Normalize line endings
  text = text.replace(/\r\n/g, '\n').replace(/\r/g, '\n');

  // Collapse 3+ blank lines down to 2
  text = text.replace(/\n{3,}/g, '\n\n');

  // Trim trailing whitespace on each line
  text = text.split('\n').map(l => l.replace(/[ \t]+$/g, '')).join('\n');

  // Lightly mark lines that look like ALL-CAPS headings as markdown ## headings
  // (only if the line is short and stands alone between blank lines)
  const lines = text.split('\n');
  const out = [];
  for (let i = 0; i < lines.length; i++) {
    const l = lines[i];
    const prev = i > 0 ? lines[i-1].trim() : '';
    const next = i < lines.length - 1 ? lines[i+1].trim() : '';
    const trimmed = l.trim();
    const isShort = trimmed.length > 0 && trimmed.length <= 80;
    const isCappy = /^[A-Z0-9][A-Z0-9 .,:;'"\-—()\/&]{2,}$/.test(trimmed);
    const isolated = prev === '' && next === '';
    if (isShort && isCappy && isolated) {
      out.push('## ' + trimmed);
    } else {
      out.push(l);
    }
  }

  const front = `# Asimov v2.13\n\n` +
    `> Converted from \`asimov_v2.13.pdf\` via pdf-parse on ${new Date().toISOString().slice(0,10)}.\n` +
    `> Text extraction only — original layout, tables, and figures are not preserved.\n` +
    `> Source PDF: ${path.basename(SRC)} — ${data.numpages} pages.\n\n---\n\n`;

  fs.writeFileSync(DST, front + out.join('\n'));
  console.error(`wrote ${DST}: ${data.numpages} pages, ${out.length} lines, ${fs.statSync(DST).size} bytes`);
}).catch(err => {
  console.error('conversion failed:', err);
  process.exit(1);
});

